INSERT INTO products (slug, category_id, name_en, name_ru, name_kk, name_tr, description_en, description_ru, description_kk, description_tr, price, image_url, sort_order) VALUES (
  'pack-cherry-brownie',
  (SELECT id FROM categories WHERE slug = 'packaged-desserts'),
  'Cherry Brownie',
  'Вишневый брауни',
  'Шие брауни',
  'Vişneli Brownie',
  'Rich chocolate brownie with deep cocoa and dark chocolate flavor, complemented by a juicy cherry layer. Dense, chewy, and truly chocolatey.',
  'Насыщенный шоколадный брауни с глубоким вкусом какао и тёмного шоколада, дополненный сочной вишнёвой прослойкой. Плотный, тягучий и по-настоящему шоколадный десерт.',
  'Какао мен қара шоколадтың терең дәмі бар, шие қабатымен толықтырылған бай шоколад брауни. Тығыз, созылмалы және шынымен шоколадты десерт.',
  'Yoğun kakao ve bitter çikolata aromalı, sulu vişne katmanlı zengin brownie. Yoğun, yapışkan ve gerçekten çikolatalı bir tatlı.',
  2500,
  '/products/cherry-brownie.png',
  1
) ON CONFLICT (slug) DO UPDATE SET
