INSERT INTO products (slug, category_id, name_en, name_ru, name_kk, name_tr, description_en, description_ru, description_kk, description_tr, price, image_url, sort_order) VALUES (
  'pack-pistachio-raspberry',
  (SELECT id FROM categories WHERE slug = 'packaged-desserts'),
  'Pistachio Raspberry',
  'Фисташково-малиновый',
  'Фисташка-малина',
  'Fıstıklı Ahududulu',
  'Delicate pistachio sponge, airy cream and soft raspberry layer. Juicy, aromatic and perfectly balanced taste.',
  'Нежный фисташковый бисквит, воздушный крем и мягкая малиновая прослойка. Сочный, ароматный и идеально сбалансированный вкус.',
  'Жұмсақ фисташка бисквиті, жеңіл крем және жұмсақ таңқурай қабаты. Шырынды, хош иісті және тамаша теңдестірілген дәм.',
  'Hafif fıstıklı kek, havadar krema ve yumuşak ahududu katmanı. Sulu, aromatik ve mükemmel dengelenmiş bir lezzet.',
  2500,
  '/products/pistachio-raspberry.png',
  2
