INSERT INTO products (slug, category_id, name_en, name_ru, name_kk, name_tr, description_en, description_ru, description_kk, description_tr, price, image_url, sort_order) VALUES (
  'pack-oreo',
  (SELECT id FROM categories WHERE slug = 'packaged-desserts'),
  'Oreo',
  'Oreo',
  'Oreo',
  'Oreo',
  'Delicate dessert with beloved Oreo flavor: creamy texture, chocolate base and cookie pieces in every layer. Rich, harmonious and soft taste.',
  'Нежный десерт с любимым вкусом Oreo: сливочная текстура, шоколадная основа и кусочки печенья в каждом слое. Насыщенный, гармоничный и мягкий вкус.',
  'Oreo дәмі бар нәзік десерт: кремді текстура, шоколад негізі және әр қабатта печенье үзінділері. Бай, үйлесімді және жұмсақ дәм.',
  'Sevilen Oreo lezzetli zarif tatlı: kremamsı doku, çikolatalı taban ve her katmanda bisküvi parçaları. Zengin, uyumlu ve yumuşak bir tat.',
  2500,
  '/products/oreo-dessert.png',
  3
